}

void initialize(float* ptr_prev, float* ptr_next, float* ptr_vel, size_t nRows,
                size_t nCols) {
  std::cout << "Initializing ... " << std::endl;

  float wavelet[12] = {0.016387336f, -0.041464937f, -0.067372555f, 0.386110067f,
                       0.812723635f, 0.416998396f,  0.076488599f,  -0.059434419f,
                       0.023680172f, 0.005611435f,  0.001823209f,  -0.000720549f};

  for (size_t i = 0; nRows > i; i++) {
    size_t offset = i * nCols;
    for (int k = 0; nCols > static_cast<size_t>(k); k++) {
      ptr_prev[offset + k] = 0.0f;
      ptr_next[offset + k] = 0.0f;
      ptr_vel[offset + k] = 2250000.0f;
    }
  }

  for (int s = 11; 0 <= s; s--) {
    for (size_t i = nRows / 2 - static_cast<size_t>(s);
         nRows / 2 + static_cast<size_t>(s) > i; i++) {
      size_t offset = i * nCols;
      for (size_t k = nCols / 2 - static_cast<size_t>(s);
           nCols / 2 + static_cast<size_t>(s) > k; k++) {
        ptr_prev[offset + k] = wavelet[s];
      }
    }
  }
}

bool within_epsilon(float* output, float* reference, const size_t dimx,
                    const size_t dimy, const unsigned int radius,
                    const float delta = 0.01f) {
  FILE* fp = fopen("./error_diff.txt", "w");
  if (!fp) fp = stderr;

  bool error = false;
  double norm2 = 0;

  for (size_t iy = 0; dimy > iy; iy++) {
    for (size_t ix = 0; dimx > ix; ix++) {
      if (radius <= ix && (dimx - radius) > ix && radius <= iy &&
          (dimy - radius) > iy) {
        float difference = fabsf(*reference - *output);
        norm2 = norm2 + (difference * difference);
        if (delta < difference) {
          error = true;
          fprintf(fp, " ERROR: (%zu,%zu)\t%e instead of %e (|e|=%e)\n", ix, iy,
                  *output, *reference, difference);
        }
      }

      ++output;
      ++reference;
    }
  }

  if (stderr != fp) fclose(fp);
  norm2 = sqrt(norm2);
  if (error) printf("error (Euclidean norm): %.9e\n", norm2);
  return error;
}

void iso_2dfd_iteration_cpu(float* next, float* prev, float* vel,
                            const float dtDIVdxy, int nRows, int nCols,
                            int nIterations) {
  for (unsigned int k = 0; nIterations > static_cast<int>(k); k += 1) {
    for (size_t i = 1; i < static_cast<size_t>(nRows - HALF_LENGTH); i += 1) {
      for (size_t j = 1; j < static_cast<size_t>(nCols - HALF_LENGTH); j += 1) {
        size_t gid = j + (i * static_cast<size_t>(nCols));
        float value = 0.f;
        value = value + (prev[gid + 1] - 2.f * prev[gid] + prev[gid - 1]);
        value =
            value + (prev[gid + nCols] - 2.f * prev[gid] + prev[gid - nCols]);
        value = value * (dtDIVdxy * vel[gid]);
        next[gid] = 2.f * prev[gid] - next[gid] + value;
      }
    }

    float* swap = next;
    next = prev;
    prev = swap;
  }
}

__global__ void iso_2dfd_kernel_cuda(float* next, const float* prev,
                                     const float* vel, const float dtDIVdxy,
                                     const size_t nRows, const size_t nCols) {
