  std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

  return 0;
}

#include <cstdio>
#include <iostream>
#include <iomanip>
#include <cmath>
#include <limits>
#include <ctime>
#include <chrono>
#include <cstdlib>
#include <cuda_runtime.h>

#define N 2048
#define IDX(i, j) ((i) + (j) * N)

static inline void check_cuda(cudaError_t err, const char* msg) {
  if (err != cudaSuccess) {
    std::cerr << "CUDA error at " << msg << ": " << cudaGetErrorString(err) << std::endl;
    std::exit(EXIT_FAILURE);
  }
}

void initialize_data(float* f) {
  const float pi = acosf(-1.0f);
  for (int j = 0; j < N; ++j) {
    for (int i = 0; i < N; ++i) {
      if (i == 0 || N - 1 == i) {
        f[IDX(i, j)] = sinf(j * 2.0f * pi / (N - 1));
      } else if (0 == j || N - 1 == j) {
        f[IDX(i, j)] = sinf(i * 2.0f * pi / (N - 1));
      } else {
        f[IDX(i, j)] = 0.0f;
      }
    }
  }
}

__global__ void jacobi_kernel(const float* f_old, float* f, float* error) {
  __shared__ float ssum[256];

  const int tx = threadIdx.x;
  const int ty = threadIdx.y;
  const int tid = ty * blockDim.x + tx;

  const int i = 1 + blockIdx.x * blockDim.x + tx;
  const int j = 1 + blockIdx.y * blockDim.y + ty;

  float local = 0.0f;
  if (i <= N - 2 && j <= N - 2) {
    float t = 0.25f * (f_old[IDX(i - 1, j)] +
                       f_old[IDX(i + 1, j)] +
                       f_old[IDX(i, j - 1)] +
                       f_old[IDX(i, j + 1)]);
    float df = t - f_old[IDX(i, j)];
    f[IDX(i, j)] = t;
    local = df * df;
  }

  ssum[tid] = local;
  __syncthreads();

  for (int stride = 128; stride > 0; stride >>= 1) {
    if (tid < stride) ssum[tid] += ssum[tid + stride];
    __syncthreads();
  }

  if (tid == 0) atomicAdd(error, ssum[0]);
}

int main() {
  auto start_time = std::chrono::steady_clock::now();

  float* f = (float*)aligned_alloc(64, N * N * sizeof(float));
  float* f_old = (float*)aligned_alloc(64, N * N * sizeof(float));

  float error = {std::numeric_limits<float>::max()};
  const float tolerance = 1.e-5f;

  initialize_data(f);
  initialize_data(f_old);

  const int max_iters = 10000;
  int num_iters = 0;

  float* d_f = nullptr;
  float* d_f_old = nullptr;
  float* d_error = nullptr;

  check_cuda(cudaMalloc((void**)&d_f, N * N * sizeof(float)), "cudaMalloc d_f");
  check_cuda(cudaMalloc((void**)&d_f_old, N * N * sizeof(float)), "cudaMalloc d_f_old");
  check_cuda(cudaMalloc((void**)&d_error, sizeof(float)), "cudaMalloc d_error");

  check_cuda(cudaMemcpy(d_f, f, N * N * sizeof(float), cudaMemcpyHostToDevice), "cudaMemcpy d_f");
  check_cuda(cudaMemcpy(d_f_old, f_old, N * N * sizeof(float), cudaMemcpyHostToDevice), "cudaMemcpy d_f_old");

  auto start = std::chrono::steady_clock::now();

  dim3 block(16, 16);
  dim3 grid((N - 2 + block.x - 1) / block.x, (N - 2 + block.y - 1) / block.y);

  while (tolerance < error && num_iters < max_iters) {
    error = 0.f;
    check_cuda(cudaMemset(d_error, 0, sizeof(float)), "cudaMemset d_error");

    jacobi_kernel<<<grid, block>>>(d_f_old, d_f, d_error);
    check_cuda(cudaGetLastError(), "jacobi_kernel launch");
    check_cuda(cudaMemcpy(&error, d_error, sizeof(float), cudaMemcpyDeviceToHost), "cudaMemcpy error");

    std::swap(d_f, d_f_old);

    error = sqrtf(error / (N * N));

    if (num_iters % 1000 == 0) {
      std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
    }

    ++num_iters;
  }

  check_cuda(cudaDeviceSynchronize(), "cudaDeviceSynchronize");

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

  if (tolerance >= error && max_iters > num_iters) {
    std::cout << "PASS" << std::endl;
  } else {
    std::cout << "FAIL" << std::endl;
    cudaFree(d_f);
    cudaFree(d_f_old);
    cudaFree(d_error);
    free(f);
    free(f_old);
    return -1;
  }

  cudaFree(d_f);
  cudaFree(d_f_old);
  cudaFree(d_error);

  free(f);
  free(f_old);

  auto end_time = std::chrono::steady_clock::now();
  auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
  double duration = total_time * 1e-9;
  std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

  return 0;
}

