__global__ void jacobi_kernel(const float* __restrict__ f_old,
                              float* __restrict__ f,
                              float* __restrict__ error) {
  __shared__ float shmem[256];
  const int tid = threadIdx.x;
  const int total = (N - 2) * (N - 2);
  const int global_tid = blockIdx.x * blockDim.x + tid;
  const int stride = gridDim.x * blockDim.x;

  float local_sum = 0.0f;

  for (int k = global_tid; k < total; k += stride) {
    int i = (k % (N - 2)) + 1;
    int j = (k / (N - 2)) + 1;

    float t = 0.25f * (f_old[IDX(i - 1, j)] +
                       f_old[IDX(i + 1, j)] +
                       f_old[IDX(i, j - 1)] +
                       f_old[IDX(i, j + 1)]);
    float diff = t - f_old[IDX(i, j)];
    f[IDX(i, j)] = t;
    local_sum += diff * diff;
  }

  shmem[tid] = local_sum;
  __syncthreads();

  for (int s = blockDim.x / 2; s > 0; s >>= 1) {
    if (tid < s) {
      shmem[tid] += shmem[tid + s];
    }
    __syncthreads();
  }

  if (tid == 0) {
    atomicAdd(error, shmem[0]);
  }
}

__global__ void copy_interior_kernel(const float* __restrict__ f,
                                     float* __restrict__ f_old) {
  const int total = (N - 2) * (N - 2);
  int k = blockIdx.x * blockDim.x + threadIdx.x;
  if (k < total) {
    int i = (k % (N - 2)) + 1;
    int j = (k / (N - 2)) + 1;
    f_old[IDX(i, j)] = f[IDX(i, j)];
  }
}

